  { q:'540 にできるだけ小さい自然数をかけて、ある整数の2乗にしたい。かける数は？', sub:'素因数分解（応用）', level:'★★★', hint:'指数が奇数の素因数に注目', type:'free', ans:'15', altAns:['15'], explain:'【考え方】指数を偶数にする。\n【手順】540=2²×3³×5。足りないのは3と5 → 3×5=15\n【ポイント】540×15=8100=90²。' },
  { q:'1個 a 円のりんご5個と、1本 b 円のジュース3本を買った代金は？（円）', sub:'数量を文字で', level:'★★☆', hint:'単価×個数の和', type:'choice', choices:['5a+3b','a5+b3','8ab','15ab'], ans:'5a+3b', explain:'【考え方】それぞれの代金をたす。\n【手順】りんご5a円＋ジュース3b円＝5a+3b\n【ポイント】数字は文字の前に書く（5a）。' },
  { q:'n を整数とするとき、必ず偶数になる式はどれ？', sub:'文字式（数の性質）', level:'★★★', hint:'2×(整数)は必ず偶数', type:'choice', choices:['2n','2n+1','n+2','n²'], ans:'2n', explain:'【考え方】偶数＝2×整数。\n【手順】2nは2の倍数で必ず偶数。2n+1は奇数、n+2やn²はnしだい\n【ポイント】偶数は2n、奇数は2n+1で表す。' },
  { q:'マッチ棒で正方形を横に n 個つくる（1個=4本, 2個=7本, 3個=10本…）。棒の本数を n の式で表すと？', sub:'文字式（規則性）', level:'★★★', hint:'増え方（公差）に注目', type:'choice', choices:['3n+1','4n','3n','4n-1'], ans:'3n+1', explain:'【考え方】1個めは4本、以降は3本ずつ増える。\n【手順】4+3(n-1)=3n+1\n【ポイント】「最初の数＋増える数×(個数-1)」を整理。' },
  { q:'縦 a cm、横 b cm の長方形の周の長さは？（cm）', sub:'数量を文字で', level:'★★☆', hint:'たて2つ＋よこ2つ', type:'choice', choices:['2a+2b','ab','a+b','2ab'], ans:'2a+2b', explain:'【考え方】周＝(縦＋横)×2。\n【手順】2(a+b)=2a+2b\n【ポイント】abは面積。周と面積を混同しない。' },
  { q:'x = -3 のとき、x² - 2x の値は？', sub:'式の値', level:'★★★', hint:'代入は()で囲む', type:'free', ans:'15', altAns:['15'], explain:'【考え方】xに-3を代入。累乗を先に。\n【手順】(-3)²-2×(-3)=9+6=15\n【ポイント】-2x=-2×(-3)=+6。符号に注意。' },
  { q:'3(2x - 1) - 2(x - 4) を簡単にすると？', sub:'文字式（計算）', level:'★★★', hint:'分配→同類項', type:'choice', choices:['4x+5','4x-5','4x+11','8x+5'], ans:'4x+5', explain:'【考え方】分配法則でかっこを外し、同類項をまとめる。\n【手順】6x-3-2x+8 → (6x-2x)+(-3+8)=4x+5\n【ポイント】-2×(-4)=+8 を忘れない。' },
  { q:'x/3 + x/2 を1つの分数にまとめると？', sub:'文字式（計算）', level:'★★★', hint:'通分（分母6）', type:'choice', choices:['5x/6','2x/5','x/5','5x/5'], ans:'5x/6', explain:'【考え方】分母を6にそろえて足す。\n【手順】2x/6 + 3x/6 = 5x/6\n【ポイント】分子どうしを足す。分母はそのまま。' },
  { q:'1個120円のりんごを x 個買い、1000円札を出す。おつりが200円以上になることを不等式で表すと？', sub:'不等式', level:'★★★', hint:'おつり＝出した金額-代金', type:'choice', choices:['1000-120x≧200','120x≧200','1000-120x≦200','120x+200≦1000'], ans:'1000-120x≧200', explain:'【考え方】おつり＝1000-120x。これが200以上。\n【手順】1000-120x ≧ 200\n【ポイント】「以上」は≧、「以下」は≦。' },
  { q:'(-24) ÷ (-2³) - (-5) を計算しよう', sub:'四則の順序', level:'★★★', hint:'累乗→乗除→加減', type:'choice', choices:['8','-2','-8','2'], ans:'8', explain:'【考え方】-2³を先に、次にわり算、最後にひき算。\n【手順】-2³=-8。-24÷(-8)=3。3-(-5)=8\n【ポイント】-(-5)=+5。順序と符号に注意。' },
  { q:'(-1/2)² の値は？', sub:'累乗', level:'★★☆', hint:'分数も2回かける', type:'choice', choices:['1/4','-1/4','1/2','-1/2'], ans:'1/4', explain:'【考え方】(-1/2)を2回かける。\n【手順】(-1/2)×(-1/2)=1/4（負×負=正）\n【ポイント】かっこつきなので符号も2乗される。' }
